+    }
+    if exp_recv.repair_count != act_recv.repair_count {
+        return Err(mismatch(
+            "received.repair_count",
+            exp_recv.repair_count,
+            act_recv.repair_count,
+        ));
+    }
+    if exp_recv.truncated != act_recv.truncated {
+        return Err(mismatch(
+            "received.truncated",
+            exp_recv.truncated,
+            act_recv.truncated,
+        ));
+    }
+    compare_prefix(
+        "received.esis",
