+
+    let exp_peel = &expected.peeling;
+    let act_peel = &actual.peeling;
+    if exp_peel.solved != act_peel.solved {
+        return Err(mismatch("peeling.solved", exp_peel.solved, act_peel.solved));
+    }
+    if exp_peel.truncated != act_peel.truncated {
+        return Err(mismatch(
